import math
from dataclasses import dataclass
from typing import Set

oo = float("inf")


@dataclass(frozen=True)
class Interval:
    """A class to describe a closed interval on the Real line"""

    minimum: float
    maximum: float

    @property
    def closure(self) -> "Interval":
        return Interval(self.minimum, self.maximum)

    @property
    def is_empty(self) -> bool:
        return self.maximum < self.minimum

    @property
    def boundary(self) -> Set[float]:
        if self.is_empty:
            return set()
        return {
            bound for bound in (self.minimum, self.maximum) if not math.isnan(bound)
        }

    def __contains__(self, item: float) -> bool:
        return self.minimum <= item <= self.maximum
